#include <bits/stdc++.h>
using namespace std;

class Solution {
    static const int MOD = 1e9 + 7;
    static const int N = 5001;
    int C[N][N];
    bool precomputed = false;

public:
    void computeDP() {
        if (precomputed) return; // Compute only once
        precomputed = true;
        for (int n = 0; n < N; n++) {
            C[n][0] = C[n][n] = 1;
            for (int k = 1; k < n; k++) {
                C[n][k] = (C[n - 1][k - 1] + C[n - 1][k]) % MOD;
            }
        }
    }

    int nCr(int n, int k) {
        if (k < 0 || k > n) return 0;
        return C[n][k];
    }

    int compute(int n, int k) {
        computeDP();  // ✅ Build Pascal’s triangle once
        if (n < 2) return 0;
        long long part1 = nCr(n - 2, k / 2);
        long long part2 = nCr(n - 2, (k - 1) / 2);
        return (int)((2LL * part1 % MOD * part2) % MOD);
    }
};

