    if (precomputed) return;
    precomputed = 1;
    fact[0] = 1;
    for (int i = 1; i < N; i++)
        fact[i] = (fact[i - 1] * i) % MOD;

    invFact[N - 1] = modPow(fact[N - 1], MOD - 2);
    for (int i = N - 2; i >= 0; i--)
        invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
}

