class Solution {
    static final int MOD = 1_000_000_007;
    static final int N = 5001;
    static long[] fact = new long[N];
    static long[] invFact = new long[N];
    static boolean precomputed = false;

    // Fast exponentiation (a^b mod M)
    private static long modPow(long a, long b) {
        long res = 1;
        while (b > 0) {
            if ((b & 1) == 1) res = (res * a) % MOD;
            a = (a * a) % MOD;
            b >>= 1;
        }
        return res;
    }

    // Precompute factorials and inverse factorials
    private static void precompute() {
        if (precomputed) return;
        precomputed = true;
        fact[0] = 1;
        for (int i = 1; i < N; i++) fact[i] = (fact[i - 1] * i) % MOD;

        invFact[N - 1] = modPow(fact[N - 1], MOD - 2);
        for (int i = N - 2; i >= 0; i--) invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
    }

    private static long nCr(int n, int k) {
        if (k < 0 || k > n) return 0;
        return (((fact[n] * invFact[k]) % MOD) * invFact[n - k]) % MOD;
    }

    public int compute(int n, int k) {
        precompute();
        if (n < 2) return 0;
        long part1 = nCr(n - 2, k / 2);
        long part2 = nCr(n - 2, (k - 1) / 2);
        return (int) ((2L * part1 % MOD * part2) % MOD);
    }
}

