class Solution {
    static MOD = 1_000_000_007n;
    static N = 5001;
    static fact = new Array(Solution.N).fill(1n);
    static invFact = new Array(Solution.N).fill(1n);
    static precomputed = false;

    static modPow(a, b) {
        let res = 1n;
        while (b > 0n) {
            if (b & 1n) res = (res * a) % Solution.MOD;
            a = (a * a) % Solution.MOD;
            b >>= 1n;
        }
        return res;
    }

    static precompute() {
        if (Solution.precomputed) return;
        Solution.precomputed = true;
        for (let i = 1; i < Solution.N; i++) {
            Solution.fact[i] = (Solution.fact[i - 1] * BigInt(i)) % Solution.MOD;
        }
        Solution.invFact[Solution.N - 1] = Solution.modPow(Solution.fact[Solution.N - 1], Solution.MOD - 2n);
        for (let i = Solution.N - 2; i >= 0; i--) {
            Solution.invFact[i] = (Solution.invFact[i + 1] * BigInt(i + 1)) % Solution.MOD;
        }
    }

    static nCr(n, k) {
        if (k < 0 || k > n) return 0n;
        return (Solution.fact[n] * Solution.invFact[k] % Solution.MOD * Solution.invFact[n - k]) % Solution.MOD;
    }

    compute(n, k) {
        Solution.precompute();
        if (n < 2) return 0;
        let part1 = Solution.nCr(n - 2, Math.floor(k / 2));
        let part2 = Solution.nCr(n - 2, Math.floor((k - 1) / 2));
        return Number((2n * part1 % Solution.MOD * part2) % Solution.MOD);
    }
}
